### Use Default Typed Lexical Editor State in TypeScript

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/overview.mdx

This example illustrates the usage of `DefaultTypedEditorState` to type the entire editor JSON. This type conveniently includes all node types associated with PayloadCMS's `defaultFeatures`, providing a streamlined way to ensure type safety for common rich text configurations without listing each node explicitly.

```ts
import type { DefaultTypedEditorState } from '@payloadcms/richtext-lexical'

const editorState: DefaultTypedEditorState = {
  root: {
    type: 'root',
    direction: 'ltr',
    format: '',
    indent: 0,
    version: 1,
    children: [
      {
        children: [
          {
            detail: 0,
            format: 0,
            mode: 'normal',
            style: '',
            text: 'Some text. Every property here is fully-typed',
            type: 'text',
            version: 1,
          },
        ],
        direction: 'ltr',
        format: '',
        indent: 0,
        type: 'paragraph',
        textFormat: 0,
        version: 1,
      },
    ],
  },
}
```

